'use client';

import React, { useState } from 'react';
import Navbar from './components/layout/Navbar';
import Sidebar from './components/layout/Sidebar';
import FileUploader from './components/FileUploader';
import FileList from './components/files/FileList';
import FilePreview from './components/FilePreview';
import CreateFolderModal from './components/modals/CreateFolderModal';
import { FileItem } from './types';

export default function Home() {
  const [files, setFiles] = useState<FileItem[]>([
    {
      id: '1',
      name: '文档',
      type: 'folder',
      size: 0,
      lastModified: Date.now(),
      isFolder: true
    },
    {
      id: '2',
      name: '图片',
      type: 'folder',
      size: 0,
      lastModified: Date.now() - 86400000,
      isFolder: true
    },
    {
      id: '3',
      name: '视频',
      type: 'folder',
      size: 0,
      lastModified: Date.now() - 172800000,
      isFolder: true
    },
    {
      id: '4',
      name: 'README.md',
      type: 'text/markdown',
      size: 1024,
      lastModified: Date.now() - 259200000,
      url: '#'
    }
  ]);
  const [selectedFile, setSelectedFile] = useState<FileItem | null>(null);
  const [selectedSection, setSelectedSection] = useState('all');
  const [isCreateFolderModalOpen, setIsCreateFolderModalOpen] = useState(false);
  const [usedStorage, setUsedStorage] = useState(1024 * 1024 * 100); // 100MB
  const [totalStorage, setTotalStorage] = useState(1024 * 1024 * 1024); // 1GB

  const handleFilesUploaded = (uploadedFiles: File[]) => {
    const newFiles: FileItem[] = uploadedFiles.map(file => ({
      id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
      name: file.name,
      type: file.type,
      size: file.size,
      lastModified: file.lastModified,
      url: URL.createObjectURL(file)
    }));
    setFiles(prevFiles => [...prevFiles, ...newFiles]);
    setUsedStorage(prev => prev + uploadedFiles.reduce((acc, file) => acc + file.size, 0));
  };

  const handleFileClick = (file: FileItem) => {
    if (file.isFolder) {
      // 处理文件夹点击，这里可以实现文件夹导航
      console.log('打开文件夹:', file.name);
    } else {
      setSelectedFile(file);
    }
  };

  const handleClosePreview = () => {
    setSelectedFile(null);
  };

  const handleFileDelete = (fileId: string) => {
    const fileToDelete = files.find(file => file.id === fileId);
    if (fileToDelete && !fileToDelete.isFolder) {
      setUsedStorage(prev => prev - fileToDelete.size);
    }
    setFiles(prevFiles => prevFiles.filter(file => file.id !== fileId));
  };

  const handleFileDownload = (file: FileItem) => {
    if (file.url) {
      const link = document.createElement('a');
      link.href = file.url;
      link.download = file.name;
      link.click();
    }
  };

  const handleCreateFolder = (folderName: string) => {
    const newFolder: FileItem = {
      id: Date.now().toString() + Math.random().toString(36).substr(2, 9),
      name: folderName,
      type: 'folder',
      size: 0,
      lastModified: Date.now(),
      isFolder: true
    };
    setFiles(prevFiles => [...prevFiles, newFolder]);
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-950 flex flex-col">
      <Navbar />
      <div className="flex flex-1 overflow-hidden">
        <Sidebar 
          selectedSection={selectedSection} 
          onSectionSelect={setSelectedSection}
          usedStorage={usedStorage}
          totalStorage={totalStorage}
        />
        <main className="flex-1 overflow-y-auto p-6">
          <div className="mb-6 flex items-center justify-between">
            <h2 className="text-2xl font-bold text-gray-900 dark:text-white">{selectedSection === 'all' ? '全部文件' : selectedSection}</h2>
            <div className="flex items-center gap-3">
              <button
                onClick={() => setIsCreateFolderModalOpen(true)}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors"
              >
                <svg
                  xmlns="http://www.w3.org/2000/svg"
                  width="16"
                  height="16"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="2"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <path d="M12 5v14" />
                  <path d="M5 12h14" />
                </svg>
                <span>新建文件夹</span>
              </button>
              <FileUploader onFilesUploaded={handleFilesUploaded} />
            </div>
          </div>
          <FileList 
            files={files} 
            onFileClick={handleFileClick}
            onFileDelete={handleFileDelete}
            onFileDownload={handleFileDownload}
          />
        </main>
      </div>
      {selectedFile && (
        <FilePreview file={selectedFile} onClose={handleClosePreview} />
      )}
      <CreateFolderModal 
        isOpen={isCreateFolderModalOpen} 
        onClose={() => setIsCreateFolderModalOpen(false)}
        onCreate={handleCreateFolder}
      />
    </div>
  );
}
